from pathlib import Path


def write_file_securely(filepath: str, content: str, mode: int = 0o644) -> None:
    """
    Write a file with restricted permissions.
    
    Args:
        filepath: Path to the file to write.
        content: Content to write.
        mode: File permission mode (default: owner read/write, group/other read).
    """
    path = Path(filepath)
    path.parent.mkdir(parents=True, exist_ok=True)
    
    # Write with restricted permissions
    fd = os.open(str(path), os.O_WRONLY | os.O_CREAT | os.O_TRUNC, mode)
    try:
        os.write(fd, content.strip().encode("utf-8"))
        os.write(fd, b"\n")
    finally:
        os.close(fd)
    
    print(f"  Created: {filepath} (mode: {oct(mode)})")


